import {
  createContext,
  useContext,
  useSyncExternalStore,
  type PropsWithChildren,
} from 'react';
import {
  createDefaultKangurProgressState,
  type KangurProgressState,
} from '@kangur/contracts/kangur';

import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';

type KangurMobileHomeProgressSnapshotContextValue = {
  progress: KangurProgressState;
  subscribeToProgressStore: boolean;
};

const KangurMobileHomeProgressSnapshotContext =
  createContext<KangurMobileHomeProgressSnapshotContextValue | null>(null);

const subscribeToProvidedHomeProgressSnapshot = (): (() => void) => () => {};

export const KangurMobileHomeProgressSnapshotProvider = ({
  children,
  progress,
  subscribeToProgressStore = false,
}: PropsWithChildren<{
  progress: KangurProgressState;
  subscribeToProgressStore?: boolean;
}>): React.JSX.Element => (
  <KangurMobileHomeProgressSnapshotContext.Provider
    value={{
      progress,
      subscribeToProgressStore,
    }}
  >
    {children}
  </KangurMobileHomeProgressSnapshotContext.Provider>
);

export const useKangurMobileHomeProgressSnapshot = (): KangurProgressState => {
  const providedProgressSnapshot = useContext(KangurMobileHomeProgressSnapshotContext);
  const { progressStore } = useKangurMobileRuntime();
  const shouldSubscribeToProgressStore =
    providedProgressSnapshot?.subscribeToProgressStore ?? true;
  const providedProgress = providedProgressSnapshot?.progress ?? null;

  return useSyncExternalStore(
    shouldSubscribeToProgressStore
      ? progressStore.subscribeToProgress
      : subscribeToProvidedHomeProgressSnapshot,
    shouldSubscribeToProgressStore
      ? progressStore.loadProgress
      : () => providedProgress ?? createDefaultKangurProgressState(),
    shouldSubscribeToProgressStore
      ? providedProgress
        ? () => providedProgress
        : createDefaultKangurProgressState
      : () => providedProgress ?? createDefaultKangurProgressState(),
  );
};

import {
  DeferredHomeInsightsBadgesCard,
  DeferredHomeInsightsBadgesDetailsCard,
  DeferredHomeInsightsPlanAssignmentsCard,
  DeferredHomeInsightsPlanCard,
  DeferredHomeInsightsPlanDetailsCard,
} from '../home-screen-secondary-deferred';
import {
  useHomeScreenDeferredPanelSequence,
} from '../useHomeScreenDeferredPanels';
import {
  HOME_BADGES_PANEL_SEQUENCE,
  HOME_PLAN_PANEL_SEQUENCE,
} from '../home-screen-constants';
import { HomeSecondaryInsightsBadgesSectionGroup } from './HomeSecondaryInsightsBadgesSectionGroup';
import { HomeSecondaryInsightsPlanSection } from './HomeSecondaryInsightsPlanSection';

export function HomeSecondaryInsightsBadgesAndPlanSectionGroup(): React.JSX.Element {
  const [
    areDeferredHomeInsightBadgesReady,
    areDeferredHomeInsightBadgesDetailsReady,
  ] = useHomeScreenDeferredPanelSequence(HOME_BADGES_PANEL_SEQUENCE, false);
  const [
    areDeferredHomeInsightPlanReady,
    areDeferredHomeInsightPlanDetailsReady,
    areDeferredHomeInsightPlanAssignmentsReady,
  ] = useHomeScreenDeferredPanelSequence(HOME_PLAN_PANEL_SEQUENCE, false);

  return (
    <>
      {!areDeferredHomeInsightBadgesReady ? (
        <DeferredHomeInsightsBadgesCard />
      ) : !areDeferredHomeInsightBadgesDetailsReady ? (
        <DeferredHomeInsightsBadgesDetailsCard />
      ) : (
        <HomeSecondaryInsightsBadgesSectionGroup />
      )}
      {!areDeferredHomeInsightPlanReady ? (
        <DeferredHomeInsightsPlanCard />
      ) : !areDeferredHomeInsightPlanDetailsReady ? (
        <DeferredHomeInsightsPlanDetailsCard />
      ) : !areDeferredHomeInsightPlanAssignmentsReady ? (
        <DeferredHomeInsightsPlanAssignmentsCard />
      ) : (
        <HomeSecondaryInsightsPlanSection />
      )}
    </>
  );
}

import { Text, View } from 'react-native';

import {
  OutlineLink,
  SectionCard,
} from '../homeScreenPrimitives';
import { AssignmentCard } from './AssignmentCard';
import { useKangurMobileI18n } from '../../i18n/kangurMobileI18n';
import { useKangurMobileHomeAssignments } from '../useKangurMobileHomeAssignments';
import { PLAN_ROUTE } from '../home-screen-constants';

export function HomeSecondaryInsightsPlanSection(): React.JSX.Element {
  const { copy } = useKangurMobileI18n();
  const homeAssignments = useKangurMobileHomeAssignments();

  return (
    <SectionCard
      title={copy({
        de: 'Plan zum Start',
        en: 'Plan from home',
        pl: 'Plan z ekranu głównego',
      })}
    >
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: 'Verwandle Fortschritt und gespeicherte Lektionen direkt in die nächsten Schritte.',
          en: 'Turn progress and saved lessons directly into the next steps.',
          pl: 'Zamień postęp i zapisane lekcje bezpośrednio w kolejne kroki.',
        })}
      </Text>
      {homeAssignments.assignmentItems.length === 0 ? (
        <Text style={{ color: '#475569', lineHeight: 20 }}>
          {copy({
            de: 'Es gibt noch keine Aufgaben. Öffne eine Lektion oder schließe ein Training ab, um sie zu erzeugen.',
            en: 'There are no tasks yet. Open a lesson or finish practice to generate them.',
            pl: 'Nie ma jeszcze zadań. Otwórz lekcję albo ukończ trening, aby je wygenerować.',
          })}
        </Text>
      ) : (
        <View style={{ gap: 12 }}>
          {homeAssignments.assignmentItems.map((item) => (
            <AssignmentCard key={item.assignment.id} item={item} />
          ))}
          <OutlineLink
            href={PLAN_ROUTE}
            hint={copy({
              de: 'Öffnet den vollständigen Tagesplan mit der erweiterten Aufgabenliste.',
              en: 'Opens the full daily plan with the extended task list.',
              pl: 'Otwiera pełny plan dnia z rozszerzoną listą zadań.',
            })}
            label={copy({
              de: 'Vollen Tagesplan öffnen',
              en: 'Open full daily plan',
              pl: 'Otwórz pełny plan dnia',
            })}
          />
        </View>
      )}
    </SectionCard>
  );
}

import { Text, View } from 'react-native';

import { useKangurMobileAuth } from '../../../auth/KangurMobileAuthContext';
import { type KangurMobileLocale, type KangurMobileCopy } from '../../../i18n/kangurMobileI18n';
import { type UseKangurMobileHomeDuelsPresenceResult } from '../../useKangurMobileHomeDuelsPresence';
import { ActiveRivalCard } from '../../home-duel-section-cards';
import { createKangurDuelsHref } from '../../../duels/duelsHref';
import { DeferredDuelSectionPlaceholder, DeferredDuelAdvancedSectionPlaceholder } from '../../HomeDuelSections';
import { type KangurDuelLobbyPresenceEntry } from '@kangur/contracts/kangur-duels';
import { PrimaryButton, OutlineLink } from '../../homeScreenPrimitives';

const DUELS_ROUTE = createKangurDuelsHref();

type Props = {
  areDeferredHomePanelsReady: boolean;
  areDeferredHomeDuelAdvancedReady: boolean;
  presence: UseKangurMobileHomeDuelsPresenceResult;
  copy: KangurMobileCopy;
  locale: string;
  onChallenge: (sessionId: string) => void;
};

function RivalsLoading({ copy }: { copy: KangurMobileCopy }): React.JSX.Element {
  return (
    <Text style={{ color: '#475569', lineHeight: 20 }}>
      {copy({
        de: 'Aktive Rivalen in der Lobby werden geladen.',
        en: 'Loading active rivals in the lobby.',
        pl: 'Pobieramy aktywnych rywali w lobby.',
      })}
    </Text>
  );
}

function RivalsError({
  copy,
  error,
  refresh,
}: {
  copy: KangurMobileCopy;
  error: string;
  refresh: () => void;
}): React.JSX.Element {
  return (
    <View style={{ gap: 10 }}>
      <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{error}</Text>
      <PrimaryButton
        hint={copy({
          de: 'Aktualisiert die aktiven Rivalen in der Lobby.',
          en: 'Refreshes the active rivals in the lobby.',
          pl: 'Odświeża aktywnych rywali w lobby.',
        })}
        label={copy({
          de: 'Rivalen aktualisieren',
          en: 'Refresh rivals',
          pl: 'Odśwież rywali',
        })}
        onPress={refresh}
      />
    </View>
  );
}

function RivalsEmpty({ copy }: { copy: KangurMobileCopy }): React.JSX.Element {
  return (
    <View style={{ gap: 10 }}>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: 'Gerade sind keine anderen Rivalen in der Duell-Lobby aktiv. Öffne die Lobby, um ein neues Match zu starten oder auf den nächsten Gegner zu warten.',
          en: 'There are no other rivals active in the duels lobby right now. Open the lobby to start a new match or wait for the next opponent.',
          pl: 'W tej chwili nie ma innych rywali aktywnych w lobby pojedynków. Otwórz lobby, aby wystartować z nowym meczem albo poczekać na kolejnego rywala.',
        })}
      </Text>
      <OutlineLink
        href={DUELS_ROUTE}
        hint={copy({ de: 'Öffnet die Duell-Lobby.', en: 'Opens the duels lobby.', pl: 'Otwiera lobby pojedynków.' })}
        label={copy({ de: 'Duell-Lobby öffnen', en: 'Open duels lobby', pl: 'Otwórz lobby pojedynków' })}
      />
    </View>
  );
}

function RivalItem({
  entry,
  copy,
  locale,
  presence,
  isCurrentLearner,
  onChallenge,
}: {
  entry: KangurDuelLobbyPresenceEntry;
  copy: KangurMobileCopy;
  locale: string;
  presence: UseKangurMobileHomeDuelsPresenceResult;
  isCurrentLearner: boolean;
  onChallenge: (sessionId: string) => void;
}): React.JSX.Element {
  return (
    <ActiveRivalCard
      key={entry.learnerId}
      copy={copy}
      entry={entry}
      isActionPending={presence.isActionPending}
      isCurrentLearner={isCurrentLearner}
      isPending={presence.pendingLearnerId === entry.learnerId}
      locale={locale as any}
      onChallenge={
        isCurrentLearner
          ? null
          : () => {
              void (async () => {
                const sid = await presence.createPrivateChallenge(entry.learnerId);
                if (sid !== null && sid !== '') onChallenge(sid);
              })();
            }
      }
    />
  );
}

function ActiveRivalsList({
  presence,
  copy,
  locale,
  activeDuelLearnerId,
  onChallenge,
}: {
  presence: UseKangurMobileHomeDuelsPresenceResult;
  copy: KangurMobileCopy;
  locale: KangurMobileLocale;
  activeDuelLearnerId: string | null;
  onChallenge: (sessionId: string) => void;
}): React.JSX.Element {
  return (
    <View style={{ gap: 10 }}>
        <Text style={{ color: '#475569', lineHeight: 20 }}>
          {copy({
            de: 'Das sind aktive Rivalen aus der Duell-Lobby. Öffne die Duell-Lobby, damit andere auch dich in dieser Liste sehen.',
            en: 'These are active rivals from the duels lobby. Open the duels lobby so others can also see you in this list.',
            pl: 'To aktywni rywale z lobby pojedynków. Otwórz lobby pojedynków, aby inni zobaczyli tu również Ciebie.',
          })}
        </Text>
        {presence.actionError !== null && presence.actionError !== '' && (
          <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{presence.actionError}</Text>
        )}
        {presence.entries.map((entry) => (
            <RivalItem 
                key={entry.learnerId} 
                entry={entry} 
                copy={copy} 
                locale={locale} 
                presence={presence} 
                isCurrentLearner={entry.learnerId === activeDuelLearnerId}
                onChallenge={onChallenge}
            />
        ))}
        <OutlineLink
          href={DUELS_ROUTE}
          hint={copy({ de: 'Öffnet die vollständige Duell-Lobby.', en: 'Opens the full duels lobby.', pl: 'Otwiera pełne lobby pojedynków.' })}
          label={copy({ de: 'Lobby öffnen', en: 'Open lobby', pl: 'Otwórz lobby' })}
        />
    </View>
  );
}

export function AuthenticatedHomeActiveRivalsContent({
  areDeferredHomePanelsReady,
  areDeferredHomeDuelAdvancedReady,
  presence,
  copy,
  locale,
  onChallenge,
}: Props): React.JSX.Element {
  const { session } = useKangurMobileAuth();
  const activeDuelLearnerId = session.user?.activeLearner?.id ?? session.user?.id ?? null;

  if (!areDeferredHomePanelsReady) return <DeferredDuelSectionPlaceholder />;
  if (!areDeferredHomeDuelAdvancedReady) return <DeferredDuelAdvancedSectionPlaceholder />;

  if (presence.isRestoringAuth || presence.isLoading) return <RivalsLoading copy={copy} />;
  if (presence.error !== null && presence.error !== '') return <RivalsError copy={copy} error={presence.error} refresh={() => { void presence.refresh(); }} />;

  if (presence.entries.length === 0) return <RivalsEmpty copy={copy} />;

  return (
    <ActiveRivalsList 
      presence={presence}
      copy={copy}
      locale={locale}
      activeDuelLearnerId={activeDuelLearnerId}
      onChallenge={onChallenge}
    />
  );
}

import { Text, View } from 'react-native';
import { PrimaryButton, OutlineLink } from '../../homeScreenPrimitives';
import { type useKangurMobileI18n } from '../../../i18n/kangurMobileI18n';
import { type useKangurMobileHomeDuelsInvites } from '../../useKangurMobileHomeDuelsInvites';
import { OutgoingChallengeCard } from '../../home-duel-section-cards';
import { createKangurDuelsHref } from '../../../duels/duelsHref';
import { DeferredDuelSectionPlaceholder, DeferredDuelAdvancedSectionPlaceholder } from '../../HomeDuelSections';

const DUELS_ROUTE = createKangurDuelsHref();

type Props = {
  areDeferredHomePanelsReady: boolean;
  areDeferredHomeDuelSecondaryReady: boolean;
  invites: ReturnType<typeof useKangurMobileHomeDuelsInvites>;
  copy: ReturnType<typeof useKangurMobileI18n>['copy'];
  locale: string;
  duelInviteShareError: string | null;
  sharingDuelSessionId: string | null;
  onShare: (sessionId: string) => Promise<void>;
};

function ChallengesLoading({ copy }: { copy: ReturnType<typeof useKangurMobileI18n>['copy'] }): React.JSX.Element {
  return (
    <Text style={{ color: '#475569', lineHeight: 20 }}>
      {copy({
        de: 'Gesendete private Herausforderungen werden geladen.',
        en: 'Loading sent private challenges.',
        pl: 'Pobieramy wysłane prywatne wyzwania.',
      })}
    </Text>
  );
}

function ChallengesDeferred({ copy }: { copy: ReturnType<typeof useKangurMobileI18n>['copy'] }): React.JSX.Element {
  return (
    <Text style={{ color: '#475569', lineHeight: 20 }}>
      {copy({
        de: 'Wir bereiten die aktualisierten gesendeten Herausforderungen für den nächsten Startschritt vor.',
        en: 'Preparing refreshed sent challenges for the next home step.',
        pl: 'Przygotowujemy odświeżone wysłane wyzwania na kolejny etap ekranu startowego.',
      })}
    </Text>
  );
}

function ChallengesError({
  copy,
  error,
  refresh,
}: {
  copy: ReturnType<typeof useKangurMobileI18n>['copy'];
  error: string;
  refresh: () => void;
}): React.JSX.Element {
  return (
    <View style={{ gap: 10 }}>
      <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{error}</Text>
      <PrimaryButton
        hint={copy({
          de: 'Aktualisiert die privaten Herausforderungen.',
          en: 'Refreshes the private challenges.',
          pl: 'Odświeża prywatne wyzwania.',
        })}
        label={copy({
          de: 'Herausforderungen aktualisieren',
          en: 'Refresh challenges',
          pl: 'Odśwież wyzwania',
        })}
        onPress={refresh}
      />
    </View>
  );
}

function ChallengesEmpty({ copy }: { copy: ReturnType<typeof useKangurMobileI18n>['copy'] }): React.JSX.Element {
  return (
    <View style={{ gap: 10 }}>
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: 'Du hast noch keine privaten Herausforderungen gesendet. Öffne die Lobby, um direkt einen Rivalen einzuladen.',
          en: 'You have not sent any private challenges yet. Open the lobby to invite a rival directly.',
          pl: 'Nie wysłano jeszcze prywatnych wyzwań. Otwórz lobby, aby od razu zaprosić rywala.',
        })}
      </Text>
      <OutlineLink
        href={DUELS_ROUTE}
        hint={copy({
          de: 'Öffnet die Duell-Lobby.',
          en: 'Opens the duels lobby.',
          pl: 'Otwiera lobby pojedynków.',
        })}
        label={copy({
          de: 'Duell-Lobby öffnen',
          en: 'Open duels lobby',
          pl: 'Otwórz lobby pojedynków',
        })}
      />
    </View>
  );
}

function ChallengesList({
  invites,
  copy,
  locale,
  duelInviteShareError,
  sharingDuelSessionId,
  onShare,
}: {
  invites: ReturnType<typeof useKangurMobileHomeDuelsInvites>;
  copy: ReturnType<typeof useKangurMobileI18n>['copy'];
  locale: string;
  duelInviteShareError: string | null;
  sharingDuelSessionId: string | null;
  onShare: (sessionId: string) => Promise<void>;
}): React.JSX.Element {
  if (invites.isRestoringAuth || invites.isLoading) return <ChallengesLoading copy={copy} />;
  if (invites.isDeferred && invites.outgoingChallenges.length === 0) return <ChallengesDeferred copy={copy} />;
  if (invites.error !== null && invites.error !== '') {
    return <ChallengesError copy={copy} error={invites.error} refresh={invites.refresh} />;
  }
  if (invites.outgoingChallenges.length === 0) return <ChallengesEmpty copy={copy} />;

  return (
    <View style={{ gap: 12 }}>
      {duelInviteShareError !== null && duelInviteShareError !== '' && (
        <Text style={{ color: '#b91c1c', lineHeight: 20 }}>{duelInviteShareError}</Text>
      )}
      {invites.outgoingChallenges.map((entry) => (
        <OutgoingChallengeCard
          key={entry.sessionId}
          copy={copy}
          entry={entry}
          isSharing={sharingDuelSessionId === entry.sessionId}
          locale={locale as any}
          onShare={() => onShare(entry.sessionId)}
        />
      ))}
    </View>
  );
}

export function AuthenticatedHomeOutgoingChallengesContent({
  areDeferredHomePanelsReady,
  areDeferredHomeDuelSecondaryReady,
  invites,
  copy,
  locale,
  duelInviteShareError,
  sharingDuelSessionId,
  onShare,
}: Props): React.JSX.Element {
  if (!areDeferredHomePanelsReady) return <DeferredDuelSectionPlaceholder />;
  if (!areDeferredHomeDuelSecondaryReady) return <DeferredDuelAdvancedSectionPlaceholder />;

  return (
    <ChallengesList 
      invites={invites}
      copy={copy}
      locale={locale}
      duelInviteShareError={duelInviteShareError}
      sharingDuelSessionId={sharingDuelSessionId}
      onShare={onShare}
    />
  );
}

import { Text, View } from 'react-native';
import { useRouter } from 'expo-router';
import { useKangurMobileI18n } from '../../../i18n/kangurMobileI18n';
import { useKangurMobileHomeDuelsRematches } from '../../useKangurMobileHomeDuelsRematches';
import { RecentOpponentCard } from '../../home-duel-section-cards';
import { PrimaryButton, OutlineLink, SectionCard } from '../../homeScreenPrimitives';
import { createKangurDuelsHref } from '../../../duels/duelsHref';
import { DeferredDuelSectionPlaceholder, DeferredDuelAdvancedSectionPlaceholder } from '../../HomeDuelSections';
import { formatKangurMobileScoreOperation } from '../../../scores/mobileScoreSummary';
import {
  MOBILE_DUEL_DEFAULT_DIFFICULTY,
  MOBILE_DUEL_DEFAULT_OPERATION,
  MOBILE_DUEL_DEFAULT_QUESTION_COUNT,
  MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC,
} from '../../../duels/mobileDuelDefaults';
import { getHomeDuelDifficultyLabel } from '../../homeScreenLabels';

const DUELS_ROUTE = createKangurDuelsHref();

type Props = {
  areDeferredHomeDuelAdvancedReady: boolean;
  areDeferredHomePanelsReady: boolean;
};

export function AuthenticatedHomeRematchesSection({
  areDeferredHomeDuelAdvancedReady,
  areDeferredHomePanelsReady,
}: Props): React.JSX.Element {
  const { copy, locale } = useKangurMobileI18n();
  const router = useRouter();
  const duelRematches = useKangurMobileHomeDuelsRematches({
    enabled: areDeferredHomeDuelAdvancedReady,
  });
  const openDuelSession = (sessionId: string): void => {
    router.replace(createKangurDuelsHref({ sessionId }));
  };

  let content: React.ReactNode = null;

  if (!areDeferredHomePanelsReady) {
    content = <DeferredDuelSectionPlaceholder />;
  } else if (!areDeferredHomeDuelAdvancedReady) {
    content = <DeferredDuelAdvancedSectionPlaceholder />;
  } else if (duelRematches.isRestoringAuth || duelRematches.isLoading) {
    content = (
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: 'Die letzten Rivalen werden geladen.',
          en: 'Loading recent opponents.',
          pl: 'Pobieramy ostatnich rywali.',
        })}
      </Text>
    );
  } else if (duelRematches.error !== null && duelRematches.error !== '') {
    content = (
      <View style={{ gap: 10 }}>
        <Text style={{ color: '#b91c1c', lineHeight: 20 }}>
          {duelRematches.error}
        </Text>
        <PrimaryButton
          hint={copy({
            de: 'Aktualisiert die Liste der letzten Rivalen.',
            en: 'Refreshes the list of recent opponents.',
            pl: 'Odświeża listę ostatnich rywali.',
          })}
          label={copy({
            de: 'Rivalen aktualisieren',
            en: 'Refresh opponents',
            pl: 'Odśwież rywali',
          })}
          onPress={duelRematches.refresh}
        />
      </View>
    );
  } else if (duelRematches.opponents.length === 0) {
    content = (
      <View style={{ gap: 10 }}>
        <Text style={{ color: '#475569', lineHeight: 20 }}>
          {copy({
            de: 'Noch keine letzten Rivalen. Beende dein erstes Duell, damit hier schnelle Rückkämpfe erscheinen.',
            en: 'There are no recent opponents yet. Finish your first duel to unlock quick rematches here.',
            pl: 'Nie ma jeszcze ostatnich rywali. Zakończ pierwszy pojedynek, aby odblokować tutaj szybkie rewanże.',
          })}
        </Text>
        <OutlineLink
          href={DUELS_ROUTE}
          hint={copy({
            de: 'Öffnet die Duell-Lobby.',
            en: 'Opens the duels lobby.',
            pl: 'Otwiera lobby pojedynków.',
          })}
          label={copy({
            de: 'Duell-Lobby öffnen',
            en: 'Open duels lobby',
            pl: 'Otwórz lobby pojedynków',
          })}
        />
      </View>
    );
  } else {
    content = (
      <View style={{ gap: 12 }}>
        {duelRematches.actionError !== null && duelRematches.actionError !== '' ? (
          <Text style={{ color: '#b91c1c', lineHeight: 20 }}>
            {duelRematches.actionError}
          </Text>
        ) : null}
        {duelRematches.opponents.map((entry) => (
          <RecentOpponentCard
            key={entry.learnerId}
            copy={copy}
            entry={entry}
            isPending={duelRematches.isActionPending}
            locale={locale}
            onRematch={async () => {
              const nextSessionId = await duelRematches.createRematch(
                entry.learnerId,
              );
              if (nextSessionId !== null && nextSessionId !== '') {
                openDuelSession(nextSessionId);
              }
            }}
          />
        ))}
      </View>
    );
  }

  return (
    <SectionCard
      title={copy({
        de: 'Letzte Rivalen',
        en: 'Recent opponents',
        pl: 'Ostatni rywale',
      })}
    >
      <Text style={{ color: '#475569', lineHeight: 20 }}>
        {copy({
          de: `Der schnelle Rückkampf startet mit den Standardwerten: ${formatKangurMobileScoreOperation(
            MOBILE_DUEL_DEFAULT_OPERATION,
            locale,
          )}, ${getHomeDuelDifficultyLabel(
            MOBILE_DUEL_DEFAULT_DIFFICULTY,
            locale,
          )}, ${MOBILE_DUEL_DEFAULT_QUESTION_COUNT} Fragen mit ${MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC}s pro Frage.`,
          en: `Quick rematch starts with the default setup: ${formatKangurMobileScoreOperation(
            MOBILE_DUEL_DEFAULT_OPERATION,
            locale,
          )}, ${getHomeDuelDifficultyLabel(
            MOBILE_DUEL_DEFAULT_DIFFICULTY,
            locale,
          )}, ${MOBILE_DUEL_DEFAULT_QUESTION_COUNT} questions with ${MOBILE_DUEL_DEFAULT_TIME_PER_QUESTION_SEC}s per question.`,
          pl: `Szybki rewanż startuje z domyślnym ustawieniem: ${formatKangurMobileScoreOperation(
